// Solution
function validateParamMiddleware(req, res, next) {
    if (req.params.id && !Number.isInteger(req.params.id) || req.params.id <= 0) {
        return res.status(400).send({ message: 'Invalid route parameter' });
    }
    next();
}

solutions.python:
class ValidateParamMiddleware:
    def __call__(self, req, res):
        if not req.params.id or not isinstance(req.params.id, int) or req.params.id <= 0:
            return res.status(400).send({ 'message': 'Invalid route parameter' })
        self.next(req, res)
